// ========================================
// 🧯 GUARDRAILS + CONFIDENCE FILTER
// ========================================
const input = $input.item.json;
const decisions = input.decisions || [];
const pricing = input.pricing || {};
const contentStrategy = input.content_strategy || {};

// === GUARDRAILS CONFIG ===
const GUARDRAILS = {
  max_price_increase_per_step: 20,    // % max increase
  min_price: 200,                      // SAR floor
  max_price: 820,                      // SAR ceiling
  max_discount_pct: 50,                // max discount %
  min_confidence_auto: 0.85,           // auto-execute threshold
  min_confidence_review: 0.70,         // review threshold (below = BLOCK)
  max_daily_pricing_changes: 2,        // prevent price flapping
  blocked_actions: ['delete_all_content', 'disable_sales'], // hard blocks
  require_approval: ['pricing', 'discount', 'scale_budget', 'pause_campaign']
};

// === APPROVAL CATEGORIES ===
// AUTO: content, analytics, notifications
// REVIEW: pricing, discounts, major scaling
// BLOCK: confidence < 70%, guardrail violations

const processed = decisions.map(d => {
  let execution_mode = 'AUTO';
  let blocked = false;
  let block_reason = '';
  let guardrail_flags = [];

  // 1. Hard block check
  if (GUARDRAILS.blocked_actions.includes(d.action)) {
    blocked = true;
    block_reason = 'Hard-blocked action';
    execution_mode = 'BLOCKED';
  }

  // 2. Confidence threshold
  if (!blocked) {
    if (d.confidence < GUARDRAILS.min_confidence_review) {
      execution_mode = 'BLOCKED';
      blocked = true;
      block_reason = `Confidence too low: ${Math.round(d.confidence * 100)}% (min: ${GUARDRAILS.min_confidence_review * 100}%)`;
      guardrail_flags.push('LOW_CONFIDENCE');
    } else if (d.confidence < GUARDRAILS.min_confidence_auto) {
      execution_mode = 'REVIEW';
      guardrail_flags.push('NEEDS_REVIEW');
    }
  }

  // 3. Check if target_agent requires approval
  if (!blocked && GUARDRAILS.require_approval.includes(d.target_agent)) {
    execution_mode = 'REVIEW';
    guardrail_flags.push('APPROVAL_REQUIRED');
  }

  // 4. Pricing guardrails
  if (!blocked && d.target_agent === 'pricing') {
    const recommended = pricing.recommended || 350;
    const current = pricing.current || 350;
    const changePct = Math.abs((recommended - current) / current * 100);

    if (changePct > GUARDRAILS.max_price_increase_per_step) {
      execution_mode = 'REVIEW';
      guardrail_flags.push(`PRICE_JUMP_${Math.round(changePct)}%`);
    }
    if (recommended < GUARDRAILS.min_price) {
      blocked = true;
      block_reason = `Price ${recommended} below floor ${GUARDRAILS.min_price}`;
      execution_mode = 'BLOCKED';
    }
    if (recommended > GUARDRAILS.max_price) {
      blocked = true;
      block_reason = `Price ${recommended} above ceiling ${GUARDRAILS.max_price}`;
      execution_mode = 'BLOCKED';
    }
  }

  // 5. Risk escalation
  if (!blocked && d.risk === 'high' && d.priority === 'critical') {
    execution_mode = 'REVIEW';
    guardrail_flags.push('HIGH_RISK_CRITICAL');
  }

  return {
    json: {
      ...d,
      pricing,
      content_strategy: contentStrategy,
      overall_status: input.overall_status,
      brain_timestamp: input.meta?.timestamp,
      // Guardrail outputs
      execution_mode,
      blocked,
      block_reason,
      guardrail_flags,
      confidence_pct: Math.round(d.confidence * 100)
    }
  };
});

return processed.length > 0 ? processed : [{ json: { action: 'no_decisions', target_agent: 'none', execution_mode: 'BLOCKED' } }];

